import{_ as s,c as a,o as i,ag as o}from"./chunks/framework.B0zzL8Pn.js";const k=JSON.parse('{"title":"syn-flooding","description":"","frontmatter":{},"headers":[],"relativePath":"Tech/~/security/syn-flooding.md","filePath":"Tech/~/security/syn-flooding.md","lastUpdated":1774912977000}'),t={name:"Tech/~/security/syn-flooding.md"};function n(l,e,c,p,d,r){return i(),a("div",null,e[0]||(e[0]=[o(`<h1 id="syn-flooding" tabindex="-1">syn-flooding <a class="header-anchor" href="#syn-flooding" aria-label="Permalink to &quot;syn-flooding&quot;">​</a></h1><p>tcp-3way 핸드쉐이크 과정을 잠깐들여다 보면, 클라이언트의 커넥션 요청인 <code>SYN</code> 패킷이 들어오면 <code>SYN-Backlog</code>에 저장을 하고 이후 서버가 <code>SYN-ACK</code> 를 보낸뒤 클라이언트에서 <code>ACK</code>를 보내게 되면 해당 소켓은 <code>SYN-Backlog</code>에서 <code>Listen-Backlog</code>으로 이동된다</p><p>이후 <code>accept()</code> 시스템콜을 통해 Liten-Backlog(Accept-Backlog)에 있는 소켓을 꺼내간다.</p><p>만약 여기서 클라이언트가 <code>ACK</code>를 보내지 않는다면?</p><ul><li><code>SYN-Backlog</code> 에 소켓이 계속 쌓이게 된다</li><li>설정된 큐크기 이상으로 요청이 올 경우 공간이 없어서 drop이 발생</li></ul><p>이러한 <code>syn-flooding</code>를 막는 방법으로는 백로그의 사이즈를 키우거나 syn-cookie 기능을 사용한다</p><p>리눅스 기준으로</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pjt@lima-default:/Users/pjt$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.ipv4.tcp_syncookies</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">net.ipv4.tcp_syncookies</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre></div><p><code>sysctl net.ipv4.tcp_syncookies</code> 명령어를 통해 활성여부를 확인할 수 있다</p><h2 id="syncookies" tabindex="-1">syncookies <a class="header-anchor" href="#syncookies" aria-label="Permalink to &quot;syncookies&quot;">​</a></h2><p>syncookies는 소켓을 <code>SYN-Backlog</code>에 저장하지 않아 근본적인 문제를 해결한다</p><p>큐에 데이터가 쌓이지 않는다면 고갈될 이유도 drop이 발생할 이유도 없기 때문.</p><p><strong>매커니즘</strong></p><ol><li>서버에서 SYN-ACK를 보낼때 아래 값을 HMAC으로 계산한 결과를 seq로 사용한다 <ul><li>HMAC(src_ip, src_port, dst_ip, dst_port, timestamp, 비밀키)</li><li>timestamp를 포함하여 오래된 ACK 재사용 공격을 방지한다</li></ul></li><li>클라이언트가 ACK를 보낸다. 서버는 ack - 1 값을 같은 방식으로 검증하여 정상 연결 여부를 확인한다</li></ol><h3 id="문제점" tabindex="-1">문제점 <a class="header-anchor" href="#문제점" aria-label="Permalink to &quot;문제점&quot;">​</a></h3><p>원래 SYN 패킷에 옵션 정보(SACK, Window Scale, Timestamp 등)이 담긴다.<br> SYN cookie는 SYN 패킷을 저장하지 않기 때문에 ACK가 돌아왔을 때 이옵션을 복원할 방법이 없다.</p><p><strong>Linux의 부분적 해결</strong></p><p>Timestamp 옵션은 예외적으로 매 패킷마다 echo back되는 구조(<code>TSval -&gt; TSecr</code>)를 활용한다.<br> 서버가 SYN-ACK 의 TSval 필드에 WScale, SACK 같은 정보를 담아서 보내면 클라이언트가 ACK의 TSecr를 그대로 돌려주기 때문에 이를 사용한다</p><ul><li>이 방법은 클라이언트가 Timestamp 옵션을 지원하는 경우에만 가능하다.</li></ul><p>Timestamp 옵션 구조 (kind=8)</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+-------+-------+---------------------+---------------------+</span></span>
<span class="line"><span>| Kind=8| Len=10|       TSval         |       TSecr         |</span></span>
<span class="line"><span>+-------+-------+---------------------+---------------------+</span></span>
<span class="line"><span>  1byte   1byte        4byte                 4byte</span></span></code></pre></div><ul><li><code>TSval</code>: 보내는 쪽이 찍는 현재 시각 timestamp value</li><li><code>TSecr</code>: 상대방이 보낸 <code>TSval</code>을 그대로 돌려주는 값 timestamp echo reply</li></ul>`,22)]))}const g=s(t,[["render",n]]);export{k as __pageData,g as default};
